mapper.select:
select e.id,e.username,e.name,e.status, r.name as role_name from employee e left join employee_role er ON e.id=er.employee_id left join role r ON er.role_id=r.id
and e.name like concat('%',#{name},'%') and e.username like concat('%',#{username},'%') and e.status=#{status}
order by e.id ASC

select role_id
from employee_role
where employee_id = #{employeeId}

select count(*)
from employee_role
where role_id = #{id}

mapper.insert:
insert into employee_role(
    employee_id, role_id, create_time, update_time, create_user, update_user
) VALUES(#{id}, #{roleId}, #{updateTime}, #{updateTime}, #{createUser}, #{updateUser})

mapper.update:
update employee
name=#{name}, username=#{username}, password=#{password}, status=#{status}, update_time= #{updateTime}, update_user= #{updateUser},
where id=#{id}

update employee_role
role_id= #{roleId}, update_time= #{updateTime}, update_user= #{updateUser},
where employee_id= #{employeeId}
